SELECT * FROM process_task_instance
WHERE assignee_id = #{assigneeId}
AND task_type = 'TODO'

    AND process_key = #{processKey}


    AND (process_name LIKE CONCAT('%', #{keyword}, '%') OR business_summary LIKE CONCAT('%', #{keyword}, '%'))


    AND priority = #{priority}

ORDER BY created_at DESC

SELECT * FROM process_task_instance
WHERE assignee_id = #{assigneeId}
AND task_type = 'DONE'

    AND process_key = #{processKey}


    AND action_type = #{actionType}

ORDER BY end_time DESC

SELECT * FROM process_task_instance
WHERE assignee_id = #{userId}
AND task_type = 'CC'

    AND is_read = #{isRead}

ORDER BY created_at DESC
